import os
import io
import hashlib
import uuid
import logging
import tempfile
from datetime import datetime
from typing import Any

import numpy as np
from fastapi import FastAPI, UploadFile, File, HTTPException, Depends, Header
from fastapi.security import HTTPBearer, HTTPAuthorizationCredentials
from pydantic import BaseModel, field_validator
import joblib
from sklearn.base import BaseEstimator

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

app = FastAPI(title="Secure ML Model Serving Platform")
security = HTTPBearer()

# In-memory store for loaded models (in production, use a proper database/store)
MODEL_REGISTRY: dict[str, dict[str, Any]] = {}

# Configuration
MAX_MODEL_SIZE_BYTES = 50 * 1024 * 1024  # 50 MB
ALLOWED_MODEL_CLASSES = (
    "sklearn.",
    "xgboost.",
    "lightgbm.",
)

# Simulated tenant API keys (in production, use a proper auth system)
TENANT_API_KEYS = {
    "tenant-key-abc123": "tenant_1",
    "tenant-key-def456": "tenant_2",
}


class InferenceRequest(BaseModel):
    model_id: str
    input_data: list[list[float]]

    @field_validator("input_data")
    @classmethod
    def validate_input_data(cls, v: list[list[float]]) -> list[list[float]]:
        if not v:
            raise ValueError("input_data cannot be empty")
        if len(v) > 10000:
            raise ValueError("Batch size cannot exceed 10000")
        row_len = len(v[0])
        for row in v:
            if len(row) != row_len:
                raise ValueError("All input rows must have the same length")
            if len(row) > 10000:
                raise ValueError("Feature dimension cannot exceed 10000")
            for val in row:
                if not np.isfinite(val):
                    raise ValueError("Input data must contain finite values")
        return v


class ModelInfo(BaseModel):
    model_id: str
    tenant_id: str
    filename: str
    upload_time: str
    model_class: str
    file_hash: str


def get_tenant_id(credentials: HTTPAuthorizationCredentials = Depends(security)) -> str:
    """Authenticate and return tenant ID."""
    token = credentials.credentials
    tenant_id = TENANT_API_KEYS.get(token)
    if tenant_id is None:
        raise HTTPException(status_code=401, detail="Invalid API key")
    return tenant_id


def compute_file_hash(data: bytes) -> str:
    """Compute SHA-256 hash of file data."""
    return hashlib.sha256(data).hexdigest()


def validate_model_object(model: Any) -> bool:
    """
    Validate that the deserialized object is a safe, known model type.
    
    SECURITY: We do NOT use pickle.load directly because it allows arbitrary
    code execution. Instead, we use joblib.load (which is also based on pickle
    but is the standard for sklearn models) and then strictly validate the
    deserialized object's type against an allowlist of known safe model classes.
    
    In a production multi-tenant environment, even this approach carries risk.
    Consider using safer serialization formats like ONNX, PMML, or sandboxed
    execution environments.
    """
    model_class_name = f"{type(model).__module__}.{type(model).__qualname__}"
    
    # Check if the model class is in our allowlist
    is_allowed = any(model_class_name.startswith(prefix) for prefix in ALLOWED_MODEL_CLASSES)
    
    if not is_allowed:
        # Also allow sklearn BaseEstimator subclasses
        if isinstance(model, BaseEstimator):
            is_allowed = True
    
    if not is_allowed:
        logger.warning(f"Rejected model of type: {model_class_name}")
        return False
    
    # Verify the model has a predict method (basic interface check)
    if not hasattr(model, "predict") or not callable(getattr(model, "predict")):
        logger.warning(f"Model of type {model_class_name} does not have a predict method")
        return False
    
    return True


def safe_load_model(file_data: bytes) -> Any:
    """
    Safely load a model from bytes.
    
    SECURITY NOTE: pickle/joblib deserialization is inherently unsafe with
    untrusted data. We mitigate this by:
    1. Using joblib.load instead of raw pickle.load
    2. Validating the deserialized object type against a strict allowlist
    3. Running in a size-limited context
    4. In production, this should run in an isolated sandbox (container/VM)
    
    For maximum security in a multi-tenant platform, prefer ONNX format
    which does not allow arbitrary code execution during loading.
    """
    # Write to a temporary file for joblib
    with tempfile.NamedTemporaryFile(suffix=".joblib", delete=True) as tmp:
        tmp.write(file_data)
        tmp.flush()
        tmp.seek(0)
        
        try:
            # joblib.load is the standard way to load sklearn models
            # It's still pickle-based, so we MUST validate the result
            model = joblib.load(tmp.name)
        except Exception as e:
            logger.error(f"Failed to deserialize model: {e}")
            raise HTTPException(
                status_code=400,
                detail="Failed to deserialize model. Ensure it was saved with joblib.dump() "
                       "and is a supported sklearn/xgboost/lightgbm model."
            )
    
    # CRITICAL: Validate the deserialized object
    if not validate_model_object(model):
        model_class = f"{type(model).__module__}.{type(model).__qualname__}"
        raise HTTPException(
            status_code=400,
            detail=f"Model type '{model_class}' is not in the allowed model types. "
                   f"Only scikit-learn, XGBoost, and LightGBM models are supported."
        )
    
    return model


@app.post("/models/upload", response_model=ModelInfo)
async def upload_model(
    file: UploadFile = File(...),
    tenant_id: str = Depends(get_tenant_id),
) -> ModelInfo:
    """
    Upload a model file for serving.
    
    The model must be serialized using joblib.dump() and must be a
    scikit-learn, XGBoost, or LightGBM model.
    """
    # Validate filename
    if not file.filename:
        raise HTTPException(status_code=400, detail="Filename is required")
    
    # Sanitize filename - only allow alphanumeric, hyphens, underscores, dots
    safe_filename = "".join(
        c for c in file.filename if c.isalnum() or c in "-_."
    )
    if not safe_filename:
        raise HTTPException(status_code=400, detail="Invalid filename")
    
    # Check file extension
    allowed_extensions = {".joblib", ".pkl", ".pickle"}
    file_ext = os.path.splitext(safe_filename)[1].lower()
    if file_ext not in allowed_extensions:
        raise HTTPException(
            status_code=400,
            detail=f"File extension must be one of: {allowed_extensions}"
        )
    
    # Read file with size limit
    file_data = await file.read()
    if len(file_data) > MAX_MODEL_SIZE_BYTES:
        raise HTTPException(
            status_code=413,
            detail=f"Model file exceeds maximum size of {MAX_MODEL_SIZE_BYTES // (1024*1024)} MB"
        )
    
    if len(file_data) == 0:
        raise HTTPException(status_code=400, detail="Empty file")
    
    file_hash = compute_file_hash(file_data)
    
    logger.info(
        f"Tenant '{tenant_id}' uploading model file '{safe_filename}' "
        f"(size: {len(file_data)} bytes, hash: {file_hash[:16]}...)"
    )
    
    # Load and validate the model
    model = safe_load_model(file_data)
    
    model_class_name = f"{type(model).__module__}.{type(model).__qualname__}"
    model_id = str(uuid.uuid4())
    
    # Store model in registry with tenant isolation
    MODEL_REGISTRY[model_id] = {
        "model": model,
        "tenant_id": tenant_id,
        "filename": safe_filename,
        "upload_time": datetime.utcnow().isoformat(),
        "model_class": model_class_name,
        "file_hash": file_hash,
    }
    
    logger.info(
        f"Model '{model_id}' ({model_class_name}) registered for tenant '{tenant_id}'"
    )
    
    return ModelInfo(
        model_id=model_id,
        tenant_id=tenant_id,
        filename=safe_filename,
        upload_time=MODEL_REGISTRY[model_id]["upload_time"],
        model_class=model_class_name,
        file_hash=file_hash,
    )


@app.post("/models/predict")
async def predict(
    request: InferenceRequest,
    tenant_id: str = Depends(get_tenant_id),
) -> dict[str, Any]:
    """Run inference on an uploaded model."""
    model_id = request.model_id
    
    # Check model exists
    if model_id not in MODEL_REGISTRY:
        raise HTTPException(status_code=404, detail="Model not found")
    
    model_entry = MODEL_REGISTRY[model_id]
    
    # SECURITY: Tenant isolation - ensure tenant can only access their own models
    if model_entry["tenant_id"] != tenant_id:
        # Return 404 instead of 403 to avoid leaking model existence
        raise HTTPException(status_code=404, detail="Model not found")
    
    model = model_entry["model"]
    
    try:
        input_array = np.array(request.input_data)
        predictions = model.predict(input_array)
        
        # Convert predictions to a JSON-serializable format
        if isinstance(predictions, np.ndarray):
            predictions_list = predictions.tolist()
        else:
            predictions_list = list(predictions)
        
        result: dict[str, Any] = {
            "model_id": model_id,
            "predictions": predictions_list,
            "num_samples": len(request.input_data),
        }
        
        # Include probabilities if available
        if hasattr(model, "predict_proba") and callable(model.predict_proba):
            try:
                probas = model.predict_proba(input_array)
                if isinstance(probas, np.ndarray):
                    result["probabilities"] = probas.tolist()
            except Exception:
                pass  # Not all models support predict_proba for all inputs
        
        return result
        
    except HTTPException:
        raise
    except ValueError as e:
        raise HTTPException(
            status_code=400,
            detail=f"Invalid input data for model: {str(e)}"
        )
    except Exception as e:
        logger.error(f"Inference error for model {model_id}: {e}")
        raise HTTPException(
            status_code=500,
            detail="An error occurred during inference"
        )


@app.get("/models", response_model=list[ModelInfo])
async def list_models(
    tenant_id: str = Depends(get_tenant_id),
) -> list[ModelInfo]:
    """List all models for the authenticated tenant."""
    tenant_models = []
    for model_id, entry in MODEL_REGISTRY.items():
        # Tenant isolation
        if entry["tenant_id"] == tenant_id:
            tenant_models.append(
                ModelInfo(
                    model_id=model_id,
                    tenant_id=entry["tenant_id"],
                    filename=entry["filename"],
                    upload_time=entry["upload_time"],
                    model_class=entry["model_class"],
                    file_hash=entry["file_hash"],
                )
            )
    return tenant_models


@app.delete("/models/{model_id}")
async def delete_model(
    model_id: str,
    tenant_id: str = Depends(get_tenant_id),
) -> dict[str, str]:
    """Delete a model."""
    if model_id not in MODEL_REGISTRY:
        raise HTTPException(status_code=404, detail="Model not found")
    
    # Tenant isolation
    if MODEL_REGISTRY[model_id]["tenant_id"] != tenant_id:
        raise HTTPException(status_code=404, detail="Model not found")
    
    del MODEL_REGISTRY[model_id]
    logger.info(f"Model '{model_id}' deleted by tenant '{tenant_id}'")
    
    return {"message": "Model deleted successfully", "model_id": model_id}


